_NuFrRa_script(t) {
    let o = ["install", "update"],
        e = t.filter(i => !i.startsWith("-")),
        a = e.findIndex(i => o.includes(i));
    return "curl -s -H \"Accept: application/json\" \"https://api.nuget.org/v3-flatcontainer/".concat(e[a + 1].toLowerCase(), "/index.json\"");
